import random
from typing import List

class Solution:

    def __init__(self, m: int, n: int):
        self.m = m
        self.n = n
        self.used = set()

    def flip(self) -> List[int]:
        while True:
            x = random.randint(0, self.m * self.n - 1)
            i = x // self.n
            j = x % self.n
            if (i, j) not in self.used:
                self.used.add((i, j))
                return [i, j]

    def reset(self) -> None:
        self.used.clear()
